<?php if (!defined('ABSPATH')) exit; $types=['T-shirt','Sweat','Polo','Hoodie','Casquette','Autre']; $fits=['Unisexe','Homme','Femme']; $sizes=['XS','S','M','L','XL','XXL']; ?>
<div class="wrap sc-admin"><h1>Produits</h1><form method="post" action="<?php echo esc_url(admin_url('admin-post.php')); ?>"><input type="hidden" name="action" value="shakass_save_products"><?php wp_nonce_field('shakass_save_products'); ?><div data-repeat><?php foreach ($products as $i=>$p): ?><section class="sc-card sc-repeat-item"><h2><?php echo esc_html($p['name']); ?></h2><label>Nom<input name="products[<?php echo $i; ?>][name]" value="<?php echo esc_attr($p['name']); ?>"></label><label>Slug<input name="products[<?php echo $i; ?>][slug]" value="<?php echo esc_attr($p['slug']); ?>"></label><label><input type="checkbox" name="products[<?php echo $i; ?>][active]" value="1" <?php checked(!empty($p['active'])); ?>> Actif</label><label><input type="checkbox" name="products[<?php echo $i; ?>][default]" value="1" <?php checked(!empty($p['default'])); ?>> Produit par défaut</label><label>Type<select name="products[<?php echo $i; ?>][type]"><?php foreach($types as $t) echo '<option '.selected($p['type'],$t,false).'>'.esc_html($t).'</option>'; ?></select></label><label>Description<textarea name="products[<?php echo $i; ?>][description]"><?php echo esc_textarea($p['description']); ?></textarea></label><label>Matière<input name="products[<?php echo $i; ?>][material]" value="<?php echo esc_attr($p['material']); ?>"></label><label>Grammage<input name="products[<?php echo $i; ?>][weight]" value="<?php echo esc_attr($p['weight']); ?>"></label><label>Coupe<select name="products[<?php echo $i; ?>][fit]"><?php foreach($fits as $f) echo '<option '.selected($p['fit'],$f,false).'>'.esc_html($f).'</option>'; ?></select></label><fieldset><legend>Tailles</legend><?php foreach($sizes as $s): ?><label><input type="checkbox" name="products[<?php echo $i; ?>][sizes][]" value="<?php echo esc_attr($s); ?>" <?php checked(in_array($s,$p['sizes'],true)); ?>> <?php echo esc_html($s); ?></label><?php endforeach; ?></fieldset><label>Couleurs (une par ligne : Nom | #hex)<textarea name="products[<?php echo $i; ?>][colors]"><?php foreach($p['colors'] as $c) echo esc_textarea($c['name'].' | '.$c['hex'])."\n"; ?></textarea></label></section><?php endforeach; ?></div><button class="button button-primary">Enregistrer les produits</button></form></div>
